#include <iostream>
#include <unordered_map>

using namespace std;

class Solution {
public:
    int countDuplicates(int arr[], int n) {
        unordered_map<int, int> freq;
        for (int i = 0; i < n; i++) {
            if (freq.find(arr[i]) != freq.end()) {
                freq[arr[i]]++;
            } else {
                freq[arr[i]] = 1;
            }
        }
        int count = 0;
        for (auto it = freq.begin(); it != freq.end(); it++) {
            if (it->second > 1) {
                count += it->second - 1;
            }
        }
        return count;
    }
};

int main() {
    int arr[] = {1, 2, 2, 3, 3, 3, 4, 4, 4, 4};
    int n = sizeof(arr) / sizeof(arr[0]);
    Solution s;
    cout << s.countDuplicates(arr, n) << endl;
    return 0;
}

