public class Solution {
    public int countDuplicates(int[] arr, int n) {
        java.util.HashMap<Integer, Integer> freq = new java.util.HashMap<>();
        for (int i = 0; i < n; i++) {
            if (freq.containsKey(arr[i])) {
                freq.put(arr[i], freq.get(arr[i]) + 1);
            } else {
                freq.put(arr[i], 1);
            }
        }
        int count = 0;
        for (java.util.Map.Entry<Integer, Integer> it : freq.entrySet()) {
            if (it.getValue() > 1) {
                count += it.getValue() - 1;
            }
        }
        return count;
    }
    public static void main(String[] args) {
        int[] arr = {1, 2, 2, 3, 3, 3, 4, 4, 4, 4};
        int n = arr.length;
        Solution s = new Solution();
        System.out.println(s.countDuplicates(arr, n));
    }
}

